		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Vowels&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;O&lt;/td&gt;
