		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Change to the previous letter&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;(-1)&lt;/td&gt;
